function normalizePassword(pw) {
  if (typeof pw !== 'string') return null;
  const trimmed = pw.trim();
  if (!trimmed) return null;
  return trimmed;
}

app.post('/delete-account', requireAuth, async (req, res) => {
  try {
    const password = normalizePassword(req.body && req.body.password);
    if (!password) return res.status(400).json({ error: 'Password is required' });

    const user = await db.getUserById(req.user.id);
    if (!user || user.deletedAt) return res.status(404).json({ error: 'Account not found' });
    if (!user.passwordHash) return res.status(409).json({ error: 'Password auth not available for this account' });

    const ok = await bcrypt.compare(password, user.passwordHash);
    if (!ok) return res.status(401).json({ error: 'Invalid credentials' });

    const deletionToken = crypto.randomBytes(32).toString('hex');
    const deletionTokenHash = crypto.createHash('sha256').update(deletionToken).digest('hex');

    await db.markUserDeleted(req.user.id, { deletedAt: new Date().toISOString(), deletionTokenHash });

    await db.invalidateAllUserSessions(req.user.id);

    req.session.destroy(() => {
      res.status(204).end();
    });
  } catch (err) {
    res.status(500).json({ error: 'Internal server error' });
  }
});

